import { useState, useEffect } from 'react'
import './App.css'

const CORRECT_PASSWORD = 'giftpass2026'

type TabKey = 'moodboard' | 'information-architecture' | 'wireframes' | 'hi-fi-design'

const TABS: { key: TabKey; label: string; embedUrl: string }[] = [
  {
    key: 'moodboard',
    label: 'MOODBOARD',
    embedUrl: 'https://embed.figma.com/design/t2mEO6QVUfP2vRFIzTNKw7/Gift-Pass-Embed?node-id=0-1&embed-host=share'
  },
  {
    key: 'information-architecture',
    label: 'INFORMATION ARCHITECTURE',
    embedUrl: 'https://embed.figma.com/design/t2mEO6QVUfP2vRFIzTNKw7/Gift-Pass-Embed?node-id=1-30&embed-host=share'
  },
  {
    key: 'wireframes',
    label: 'WIREFRAMES',
    embedUrl: 'https://embed.figma.com/design/t2mEO6QVUfP2vRFIzTNKw7/Gift-Pass-Embed?node-id=1-1593&embed-host=share'
  },
  {
    key: 'hi-fi-design',
    label: 'HI-FI DESIGN',
    embedUrl: 'https://embed.figma.com/design/t2mEO6QVUfP2vRFIzTNKw7/Gift-Pass-Embed?node-id=2-5756&embed-host=share'
  }
]

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false)
  const [password, setPassword] = useState('')
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(true)
  const [activeTab, setActiveTab] = useState<TabKey>('moodboard')

  useEffect(() => {
    const stored = sessionStorage.getItem('giftpass_auth')
    if (stored === 'true') {
      setIsAuthenticated(true)
    }
    setIsLoading(false)
  }, [])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError('')

    if (password === CORRECT_PASSWORD) {
      sessionStorage.setItem('giftpass_auth', 'true')
      setIsAuthenticated(true)
    } else {
      setError('Incorrect password. Please try again.')
      setPassword('')
    }
  }

  if (isLoading) {
    return (
      <div className="loading-screen">
        <div className="loader"></div>
      </div>
    )
  }

  if (!isAuthenticated) {
    return (
      <div className="login-container">
        <div className="login-card">
          <div className="login-logo">
            <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
              <rect width="48" height="48" rx="12" fill="url(#gradient)" />
              <path d="M24 12L32 20H26V28H22V20H16L24 12Z" fill="white" />
              <path d="M16 32H32V36H16V32Z" fill="white" />
              <defs>
                <linearGradient id="gradient" x1="0" y1="0" x2="48" y2="48">
                  <stop stopColor="#FF6B6B" />
                  <stop offset="1" stopColor="#4ECDC4" />
                </linearGradient>
              </defs>
            </svg>
          </div>
          <h1 className="login-title">Gift Pass</h1>
          <p className="login-subtitle">Enter password to continue</p>

          <form onSubmit={handleSubmit} className="login-form">
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter password"
              className="password-input"
              autoFocus
            />
            {error && <p className="error-message">{error}</p>}
            <button type="submit" className="submit-button">
              Unlock
            </button>
          </form>
        </div>
        <div className="login-backdrop"></div>
      </div>
    )
  }

  const currentTab = TABS.find(tab => tab.key === activeTab) || TABS[0]

  return (
    <div className="page-container">
      <header className="header">
        <div className="header-logo">
          <svg width="36" height="36" viewBox="0 0 48 48" fill="none">
            <rect width="48" height="48" rx="12" fill="url(#gradient2)" />
            <path d="M24 12L32 20H26V28H22V20H16L24 12Z" fill="white" />
            <path d="M16 32H32V36H16V32Z" fill="white" />
            <defs>
              <linearGradient id="gradient2" x1="0" y1="0" x2="48" y2="48">
                <stop stopColor="#FF6B6B" />
                <stop offset="1" stopColor="#4ECDC4" />
              </linearGradient>
            </defs>
          </svg>
          <span className="logo-text">Gift Pass</span>
        </div>
      </header>

      <main className="main-content">
        <section className="intro-section">
          <h1 className="page-title">Gift Pass Embed Preview</h1>
          <p className="intro-text">
            Welcome to the Gift Pass design preview. Below you'll find our latest Figma designs 
            showcasing the embedded gift pass experience. Feel free to explore the interactive 
            prototype and leave comments directly in Figma.
          </p>
        </section>

        <nav className="tab-navigation">
          {TABS.map(tab => (
            <button
              key={tab.key}
              className={`tab-pill ${activeTab === tab.key ? 'active' : ''}`}
              onClick={() => setActiveTab(tab.key)}
            >
              {tab.label}
            </button>
          ))}
        </nav>

        <section className="figma-section">
          <iframe
            key={activeTab}
            src={currentTab.embedUrl}
            style={{ border: '1px solid rgba(0, 0, 0, 0.1)' }}
            width="100%"
            height="800"
            allowFullScreen
            title={`Gift Pass - ${currentTab.label}`}
          />
        </section>
      </main>
    </div>
  )
}

export default App
